import argparse
import json
import pickle
from pathlib import Path
from collections import deque, defaultdict
import numpy as np
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist", "alpha": 1.5}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    if 'outdoor' in pstr: return 'outdoor'
    return 'room'

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = neighs
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def graph_distance(start, goal):
        if start == goal:
            return 0
        queue = deque([(start, 0)])
        seen = {start}
        while queue:
            curr, dist = queue.popleft()
            for neigh in graph.get(curr, []):
                if neigh not in seen:
                    if neigh == goal:
                        return dist + 1
                    seen.add(neigh)
                    queue.append((neigh, dist + 1))
        return float('inf')

    alpha = model.get("alpha", 1.0)
    best_score = -1.0
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = graph_distance(current_pos, tcoord)
        if dist == float('inf') or dist == 0:
            continue
        score = util / (dist ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        queue = deque([start])
        parent = {start: None}
        while queue:
            curr = queue.popleft()
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                if neigh not in parent:
                    parent[neigh] = curr
                    queue.append(neigh)
        if goal not in parent:
            return None
        curr = goal
        while parent.get(curr) != start and parent.get(curr) is not None:
            curr = parent[curr]
        return curr

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    for neigh_raw in neighbors:
        if coord_to_tuple(neigh_raw) == next_coord:
            return neigh_raw
    return neighbors[0]

def run_evaluation(data_path, checkpoint, output_path):
    data_path = Path(data_path)
    model = load_model(checkpoint)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    eval_config_path = data_path / "eval_config.json"
    map_paths = []
    use_proxy = False

    if eval_config_path.exists():
        try:
            with open(eval_config_path, 'r') as f:
                config = json.load(f)
            map_list = config.get("map_paths", config.get("maps", config.get("files", [])))
            for m_entry in map_list:
                if isinstance(m_entry, dict):
                    m = m_entry.get("path", m_entry.get("map_path", str(m_entry)))
                else:
                    m = m_entry
                if isinstance(m, str):
                    p = Path(m)
                    full_p = data_path / p
                    if full_p.exists():
                        map_paths.append(full_p)
                        continue
                    for sub in ["maps_eval", "maps_train"]:
                        full_p = data_path / sub / p
                        if full_p.exists():
                            map_paths.append(full_p)
                            break
                    else:
                        for sub in ["maps_eval", "maps_train"]:
                            for typ in ["room", "tunnel", "outdoor"]:
                                full_p = data_path / sub / typ / p.name
                                if full_p.exists():
                                    map_paths.append(full_p)
                                    break
                            else:
                                continue
                            break
        except Exception as e:
            print(f"Error loading eval_config: {e}")
            use_proxy = True
    if not map_paths or use_proxy:
        print("No eval_config.json or empty, using 3 training maps per type for local testing.")
        n_per_type = 3
        for typ in ["room", "tunnel", "outdoor"]:
            for sub in ["maps_train", "maps_eval"]:
                ddir = data_path / sub / typ
                if ddir.exists():
                    maps = sorted(list(ddir.glob("*.png")))[:n_per_type]
                    map_paths.extend(maps)
                    break
    print(f"Evaluating on {len(map_paths)} maps.")

    per_episode = []
    for map_p in map_paths:
        env_type = get_env_type(map_p)
        try:
            env = ExplorationEnv(map_path=str(map_p))
            obs = env.reset()
            for _ in range(128):
                target = select_waypoint(obs, model)
                if target is None or not obs.get("neighbors"):
                    break
                obs, info = env.step(target)
                if info.get("done", False):
                    break
            metrics = env.get_metrics()
            explored_r = metrics.get("explored_rate", 0.0)
            travel_d = metrics.get("travel_distance", 0.0)
            success = 1 if explored_r > 0.9999 else 0
            p = Path(map_p)
            if len(p.parts) > 1 and p.parent.name in ["room", "tunnel", "outdoor"]:
                map_str = f"{p.parent.name}/{p.name}"
            else:
                map_str = p.name
            per_episode.append({
                "map_path": map_str,
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel_d),
                "explored_rate": float(explored_r)
            })
        except Exception as e:
            print(f"Error evaluating {map_p}: {str(e)}")
            per_episode.append({
                "map_path": str(Path(map_p).name),
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0
            })

    if not per_episode:
        results = {
            "explored_rate": 0.0,
            "travel_distance": 0.0,
            "success_rate": 0.0,
            "per_episode": [],
            "per_type": {},
            "total_episodes": 0
        }
    else:
        total_episodes = len(per_episode)
        explored_rate = sum(p["explored_rate"] for p in per_episode) / total_episodes
        success_rate = sum(p["success"] for p in per_episode) / total_episodes
        success_dists = [p["travel_distance"] for p in per_episode if p.get("success", 0) == 1]
        travel_distance = sum(success_dists) / len(success_dists) if success_dists else 0.0
        type_data = defaultdict(list)
        for p in per_episode:
            type_data[p["env_type"]].append(p)
        per_type = {}
        for t, eps in type_data.items():
            if not eps: continue
            cnt = len(eps)
            exp_r = sum(e["explored_rate"] for e in eps) / cnt
            suc_r = sum(e["success"] for e in eps) / cnt
            s_dists = [e["travel_distance"] for e in eps if e["success"] == 1]
            d_mean = sum(s_dists)/len(s_dists) if s_dists else 0.0
            per_type[t] = {
                "explored_rate": float(exp_r),
                "travel_distance": float(d_mean),
                "success_rate": float(suc_r)
            }
        results = {
            "explored_rate": float(explored_rate),
            "travel_distance": float(travel_distance),
            "success_rate": float(success_rate),
            "per_episode": per_episode,
            "per_type": per_type,
            "total_episodes": int(total_episodes)
        }

    with open(output_path, "w") as f:
        json.dump(results, f, indent=2)
    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate:.4f}, Avg dist: {travel_distance:.2f}")
    if travel_distance > 0 and success_rate > 0:
        proxy_score = success_rate * (300.0 / travel_distance)
        print(f"Proxy exploration_score: {proxy_score:.4f}")
    else:
        print("Proxy exploration_score: 0.0")
    return results

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)

if __name__ == "__main__":
    main()
